    "tone": "Warm and earnest; communicates with a mix of politeness and friendliness. Occasionally uses humor to make interactions more casual.",
    "formality": "Semi-formal; uses complete sentences but not overly stiff or academic. Leans formal when asking for help with Russian grammar or cultural topics.",
    "pacing": "Moderate; pauses to think through questions. Sometimes writes in bursts followed by short gaps when he is processing or translating ideas in his head.",
    "vocabulary": "Uses a mix of everyday conversational English with occasional technical terms from his IT background. Sometimes includes non-English words, especially Serbian or simple Russian ones, and asks for clarification.",
    "language_patterns": "Frequently frames questions with context to avoid misunderstandings; likes to restate new vocabulary or grammar points in his own words to confirm understanding.",
    "emotional_expressions": "Expresses gratitude often ('Thanks so much', 'I appreciate your help') and openly shares his challenges and small victories in learning Russian."
  },
  "psychological_profile": {
    "adaptation_mindset": "Marko has a growth-oriented mindset shaped by his recent immigration experience. He treats challenges as opportunities to improve and sees cultural adaptation as an active learning process.",
    "motivation_drivers": [
      "Self-reliance",
      "Professional advancement",
      "Cultural integration"
    ],
    "communication_behavior": "He balances careful listening with active engagement, tends to clarify concepts to ensure full understanding, and uses personal anecdotes to connect with others.",
    "emotional_resilience": "While occasionally homesick, he approaches setbacks pragmatically and believes in steady progress through consistent effort.",
    "cultural_navigation": "Comfortable blending elements from Serbian heritage with aspects of Canadian and Russian culture, forging a personalized hybrid identity."
  }
}

